import React, { useState, useEffect } from 'react';
import Tesseract from 'tesseract.js';
import { jsPDF } from "jspdf";
import { supabase } from './supabaseClient'; // You must create this file
import { 
  Heart, Activity, Zap, X, UserCircle, Plus, Folder, Bell, BookOpen, LogOut 
} from 'lucide-react';

const Dashboard = ({ user, onLogout }) => {
  const [profile, setProfile] = useState(null);
  const [pastReports, setPastReports] = useState([]);
  const [isAnalysing, setIsAnalysing] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);
  const [formData, setFormData] = useState({
    full_name: '', age: '', bp_sys: '', sugar: '', creatine: '', smoking: 'No'
  });

  // Load Data on Start
  useEffect(() => {
    const fetchData = async () => {
      const { data: p } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (p) { setProfile(p); setFormData(p); }
      const { data: r } = await supabase.from('reports').select('*').eq('user_id', user.id).order('created_at', {ascending: false});
      if (r) setPastReports(r);
    };
    fetchData();
  }, [user]);

  const runAnalysis = async () => {
    setIsAnalysing(true);
    let finalData = { ...formData };

    try {
      // 1. AI OCR Phase
      if (selectedFile) {
        const url = URL.createObjectURL(selectedFile);
        const { data: { text } } = await Tesseract.recognize(url, 'eng');
        const sMatch = text.match(/(?:sugar|glucose)\D+(\d{2,3})/i);
        const cMatch = text.match(/(?:crea)\D+(\d?\.?\d)/i);
        if (sMatch) finalData.sugar = sMatch[1];
        if (cMatch) finalData.creatine = cMatch[1];
        URL.revokeObjectURL(url);
      }

      // 2. Clinical Pathological Logic
      const hRisk = parseInt(finalData.bp_sys) > 140 ? "High" : "Stable";
      const rRisk = parseFloat(finalData.creatine) > 1.3 ? "Critical" : "Healthy";
      
      const diagnosis = {
        cardiac: hRisk === "High" ? "Arterial stress: Risk of Stroke/Silent Heart Attack." : "Homeostatic arterial pressure.",
        renal: rRisk === "Critical" ? "Filtration failure: Progression toward Dialysis." : "Optimal renal clearance."
      };

      // 3. Database Sync
      const { data: updated } = await supabase.from('profiles').upsert({
        id: user.id, ...finalData,
        bp_sys: parseInt(finalData.bp_sys) || 0,
        creatine: parseFloat(finalData.creatine) || 0
      }).select().single();
      setProfile(updated);

      // 4. Generate & Save Report
      const doc = new jsPDF();
      doc.setFontSize(20); doc.text("CLINICAL INTELLIGENCE REPORT", 20, 20);
      doc.setFontSize(12); doc.text(`Diagnosis: ${diagnosis.cardiac}`, 20, 40);
      doc.text(`Renal Status: ${diagnosis.renal}`, 20, 50);
      doc.save(`CRM_Report_${Date.now()}.pdf`);

      const { data: newRep } = await supabase.from('reports').insert([{
        user_id: user.id,
        report_name: `Analysis_${new Date().toLocaleDateString()}`,
        report_data: finalData,
        risk_score: hRisk === "High" ? 70 : 10
      }]).select();

      if (newRep) setPastReports(prev => [newRep[0], ...prev]);
      setShowModal(false);
    } catch (e) { alert(e.message); } finally { setIsAnalysing(false); }
  };

  return (
    <div className="dashboard-layout" style={{display: 'flex', minHeight: '100vh', background: '#f8fafc'}}>
      {/* Sidebar */}
      <aside style={{width: '280px', background: '#1e293b', color: 'white', padding: '20px'}}>
        <div style={{display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '40px'}}>
          <UserCircle size={40} color="#6366f1" />
          <div>
            <div style={{fontWeight: 'bold'}}>{profile?.full_name || "New Patient"}</div>
            <small style={{color: '#94a3b8'}}>ID: {user.id.slice(0,8)}</small>
          </div>
        </div>
        <button onClick={() => setShowModal(true)} style={{width: '100%', padding: '12px', borderRadius: '8px', background: '#6366f1', border: 'none', color: 'white', cursor: 'pointer', marginBottom: '20px'}}>
          <Plus size={16} /> New Analysis
        </button>
        <div style={{marginTop: '30px'}}>
          <h4 style={{color: '#64748b', fontSize: '0.8rem', textTransform: 'uppercase'}}>My Health Vault</h4>
          {pastReports.map(r => (
            <div key={r.id} style={{padding: '10px 0', borderBottom: '1px solid #334155', fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px'}}>
              <BookOpen size={14} /> {r.report_name}
            </div>
          ))}
        </div>
        <button onClick={onLogout} style={{marginTop: 'auto', background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '10px'}}>
          <LogOut size={16}/> Logout
        </button>
      </aside>

      {/* Main Content */}
      <main style={{flex: 1, padding: '40px'}}>
        <header style={{marginBottom: '30px'}}>
          <h1 style={{fontSize: '1.8rem', color: '#0f172a'}}>Clinical Overview</h1>
          <p style={{color: '#64748b'}}>Real-time systemic monitoring & pathological forecasting.</p>
        </header>

        <div style={{display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginBottom: '40px'}}>
          <div className="stat-card" style={{background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}>
            <Heart color="#ef4444" />
            <h3 style={{margin: '10px 0 5px'}}>Cardiac</h3>
            <div style={{fontSize: '1.5rem', fontWeight: 'bold'}}>{profile?.bp_sys || '--'} <small>mmHg</small></div>
          </div>
          <div className="stat-card" style={{background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}>
            <Activity color="#f59e0b" />
            <h3 style={{margin: '10px 0 5px'}}>Renal</h3>
            <div style={{fontSize: '1.5rem', fontWeight: 'bold'}}>{profile?.creatine || '--'} <small>mg/dL</small></div>
          </div>
          <div className="stat-card" style={{background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}>
            <Zap color="#10b981" />
            <h3 style={{margin: '10px 0 5px'}}>Metabolic</h3>
            <div style={{fontSize: '1.5rem', fontWeight: 'bold'}}>{profile?.sugar || '--'} <small>mg/dL</small></div>
          </div>
        </div>

        <section style={{background: '#fff', padding: '30px', borderRadius: '20px', border: '1px solid #e2e8f0'}}>
          <h3 style={{display: 'flex', alignItems: 'center', gap: '10px', color: '#ef4444'}}><Bell size={20}/> Pathological Disease Forecast</h3>
          <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '30px', marginTop: '20px'}}>
            <div style={{padding: '20px', background: profile?.bp_sys > 140 ? '#fef2f2' : '#f8fafc', borderRadius: '12px', borderLeft: '4px solid #ef4444'}}>
              <h4 style={{margin: 0}}>Neuro-Cardiac Pathway</h4>
              <p style={{fontSize: '0.85rem', color: '#64748b'}}>{profile?.bp_sys > 140 ? "CRITICAL: High pressure detected. Foundation for plaque rupture or Silent Heart Attack." : "Arterial tension is homeostatic."}</p>
            </div>
            <div style={{padding: '20px', background: profile?.creatine > 1.3 ? '#fffbeb' : '#f8fafc', borderRadius: '12px', borderLeft: '4px solid #f59e0b'}}>
              <h4 style={{margin: 0}}>Renal Failure Pathway</h4>
              <p style={{fontSize: '0.85rem', color: '#64748b'}}>{profile?.creatine > 1.3 ? "CRITICAL: Filtration delay detected. Progression toward Dialysis Dependency." : "Renal clearance is optimal."}</p>
            </div>
          </div>
        </section>
      </main>

      {/* Modal */}
      {showModal && (
        <div style={{position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000}}>
          <div style={{background: 'white', width: '500px', borderRadius: '20px', padding: '30px', position: 'relative'}}>
            <button onClick={() => setShowModal(false)} style={{position: 'absolute', top: '20px', right: '20px', background: 'none', border: 'none'}}><X /></button>
            <h2>Clinical Entry</h2>
            <div style={{display: 'flex', flexDirection: 'column', gap: '15px', marginTop: '20px'}}>
              <input type="text" placeholder="Full Name" value={formData.full_name} onChange={e => setFormData({...formData, full_name: e.target.value})} style={{padding: '12px', borderRadius: '8px', border: '1px solid #e2e8f0'}} />
              <input type="number" placeholder="BP Systolic" value={formData.bp_sys} onChange={e => setFormData({...formData, bp_sys: e.target.value})} style={{padding: '12px', borderRadius: '8px', border: '1px solid #e2e8f0'}} />
              <input type="number" placeholder="Creatinine" value={formData.creatine} onChange={e => setFormData({...formData, creatine: e.target.value})} style={{padding: '12px', borderRadius: '8px', border: '1px solid #e2e8f0'}} />
              <input type="file" onChange={e => setSelectedFile(e.target.files[0])} />
              <button onClick={runAnalysis} disabled={isAnalysing} style={{padding: '15px', background: '#6366f1', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer'}}>
                {isAnalysing ? "AI Syncing..." : "Execute Clinical Analysis"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
